import { useCallback, useEffect, useRef, useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { GiftInfo } from "@sitin/api-proto/gen/archat_api/user_api";
import { useChatDetail } from "@/hooks/useChatDetail";
import { useUser } from "@/hooks/useUser";
import { useLockFn } from "@/hooks/useLockFn";
import { getAvatarUrl, CustomAvatarType, isRealHuman } from "@/utils/userUtil";
import { TimMessage, GiftMessage } from "@/types/chatMessage";
import { toast } from "@/utils/toast";
import { goBack } from "@/utils/navigation";
import IMManager from "@/services/IMManager";
import NavigationBar from "@/components/NavigationBar";
import ChatMessageList, { ChatMessageListHandler } from "./ChatMessageList";
import ChatFooter from "./ChatFooter";
import GiftList from "./GiftList";
import GiftAnimation, { GiftAnimationHandler } from "./GiftAnimation";
import ChatNextUnreadButton from "./ChatNextUnreadButton";
import CoinClaimButton from "@/components/CoinClaimButton";
import { bpTrack } from "@/tracking";
import { EventName } from "@/tracking/events";

export default function ChatDetail() {
  const location = useLocation();
  const navigate = useNavigate();
  const { conversationId, from_jump_next } = (location.state as {
    conversationId?: string;
    from_jump_next?: boolean;
  }) ?? {};
  const { userInfo, cash, setCash } = useUser();

  const messageListRef = useRef<ChatMessageListHandler>(null);
  const giftAnimationRef = useRef<GiftAnimationHandler>(null);
  const [showGiftList, setShowGiftList] = useState(false);

  const handleShowGiftAnimation = useCallback((message: TimMessage) => {
    const giftMsg = message as GiftMessage;
    giftAnimationRef.current?.showGift(giftMsg.payloadData.imageUrl);
    IMManager.markGiftRendered(message.raw);
  }, []);

  const {
    messages,
    peerUserInfo,
    isLoadingMore,
    hasMore,
    isTyping,
    sendText,
    sendGiftMessage,
    loadMore,
    scrollToBottomRef,
  } = useChatDetail(conversationId ?? "", handleShowGiftAnimation);

  scrollToBottomRef.current = () => messageListRef.current?.scrollToBottom();

  const handleBack = useCallback(() => goBack(navigate, "/chats"), [navigate]);
  const handleSend = useCallback(async (text: string) => sendText(text), [sendText]);

  const handleSendGift = useLockFn(async (gift: GiftInfo) => {
    if (!peerUserInfo?.userId) return;

    if (gift.giftCostDollar === undefined) gift.giftCostDollar = "0";
    const price = Number(parseFloat(gift.giftCostDollar).toFixed(2));
    const currentCash = cash ?? 0;

    if (currentCash < price) {
      toast.error("Insufficient balance to send this gift.");
      return;
    }

    try {
      const success = await sendGiftMessage(gift.giftId ?? "", peerUserInfo.userId, gift.giftImageUrl ?? "", price);
      if (success) {
        setCash(parseFloat((currentCash - price).toFixed(2)));
        setShowGiftList(false);
        setTimeout(() => messageListRef.current?.scrollToBottom(), 100);
      } else {
        toast.error("Failed to send gift");
      }
    } catch {
      toast.error("Failed to send gift");
    }
  });

  // 无 conversationId 时重定向
  useEffect(() => {
    if (!conversationId) {
      goBack(navigate, "/chats");
    }
  }, [conversationId, navigate]);

  // 埋点：聊天详情页展示
  useEffect(() => {
    if (!conversationId) return;
    bpTrack(EventName.pwa_chat_detail_show, {
      conversation_id: conversationId,
      target_user_id: peerUserInfo?.userId || 0,
      target_user_type: isRealHuman(peerUserInfo) ? "real" : "dh",
      from_jump_next: from_jump_next ?? false,
    });
  }, [conversationId, peerUserInfo?.userId, from_jump_next]);

  if (!conversationId) return null;

  const bgAvatarUrl = getAvatarUrl(peerUserInfo, CustomAvatarType.Mid);
  const headerTitle = isTyping
    ? "✍️Typing…"
    : (() => {
        let title = peerUserInfo?.username ?? "";
        if (import.meta.env.MODE !== "production" && peerUserInfo?.userId) {
          if (!isRealHuman(peerUserInfo)) title = `${title}-🤖`;
          title = `${title}(${peerUserInfo.userId})`;
        }
        return title;
      })();

  return (
    <div className="relative z-0 flex size-full flex-col overflow-y-hidden animate-fade-in">
      <div
        aria-hidden="true"
        className="pointer-events-none absolute inset-0 -z-10 bg-cover bg-center"
        style={{
          backgroundImage: bgAvatarUrl ? `url(${bgAvatarUrl})` : undefined,
          filter: "blur(20px)",
          willChange: "transform",
          transform: "translateZ(0) scale(1.1)",
        }}
      >
        <div className="size-full bg-[rgba(0,5,35,0.33)]" />
      </div>

      <NavigationBar title={headerTitle} onBack={handleBack} variant="dark" sticky={false} />

      <div className="relative flex flex-1 flex-col overflow-hidden">
        <ChatMessageList
          ref={messageListRef}
          messages={messages}
          peerUserInfo={peerUserInfo}
          selfUserInfo={userInfo ?? null}
          isTyping={isTyping}
          hasMore={hasMore}
          isLoadingMore={isLoadingMore}
          onLoadMore={loadMore}
          onGiftSendMore={() => setShowGiftList(true)}
        />
        <ChatNextUnreadButton conversationId={conversationId} />
      </div>

      <ChatFooter
        onSend={handleSend}
        onGift={() => {
          bpTrack(EventName.pwa_chat_gift_modal_show);
          setShowGiftList(true);
        }}
        peerUserId={peerUserInfo?.userId}
        isRealUser={isRealHuman(peerUserInfo)}
        totalEarningValue={cash}
      />
      {showGiftList && (
        <GiftList
          onClose={() => setShowGiftList(false)}
          onSend={handleSendGift}
          peerUserId={peerUserInfo?.userId}
          isRealUser={isRealHuman(peerUserInfo)}
          currentCash={cash}
        />
      )}
      <GiftAnimation ref={giftAnimationRef} />
      <CoinClaimButton />
    </div>
  );
}
